      "2008" = 47,49,66,97,44,29,55
      "2009" = 28,38,74,105,23,39,55
      "2010" = 57,42,51,76,53,57,37
      "2011" = 32,38,56,86,47,43,45
      "2012" = 34,34,46,69,29,43,31
      "2013" = 33,43,53,39,36,40,24
      "2014" = 31,44,28,69,37,8,27
